import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Ensure nullString field is null
        setNullString(csvFormat, null);
        assertFalse(csvFormat.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Set nullString field to non-null value
        setNullString(csvFormat, "NULL");
        assertTrue(csvFormat.isNullStringSet());
    }

    private void setNullString(CSVFormat format, String value) throws Exception {
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, value);
    }
}
